import { stableStringify } from '../../src/stringify.mjs';
import test from 'node:test';
import assert from 'node:assert';
test('golden stable', () => {
  assert.strictEqual(stableStringify({ b: 1, a: 2 }), stableStringify({ a: 2, b: 1 }));
  assert.strictEqual(stableStringify({ z: { b: 1, a: 2 } }), '{"z":{"a":2,"b":1}}');
  assert.strictEqual(stableStringify([3, 1, 2]), '[3,1,2]');
  assert.strictEqual(stableStringify({ b: [2, 1], a: 1 }), '{"a":1,"b":[2,1]}');
});
